const crypto = require('crypto');

// Configure in n8n as an environment variable or variable. Do not hardcode
// service-account JSON in exported workflows.
const rawServiceAccount =
  process.env.FIREBASE_SERVICE_ACCOUNT_KEY ||
  $vars.FIREBASE_SERVICE_ACCOUNT_KEY;

if (!rawServiceAccount) {
  throw new Error('Missing FIREBASE_SERVICE_ACCOUNT_KEY in n8n environment or variables');
}

let SERVICE_ACCOUNT;
try {
  SERVICE_ACCOUNT = JSON.parse(rawServiceAccount);
} catch (e) {
  throw new Error('FIREBASE_SERVICE_ACCOUNT_KEY is not valid JSON: ' + e.message);
}

if (!SERVICE_ACCOUNT.project_id || !SERVICE_ACCOUNT.client_email || !SERVICE_ACCOUNT.private_key) {
  throw new Error('FIREBASE_SERVICE_ACCOUNT_KEY must include project_id, client_email, and private_key');
}

// -- Level display names -------------------------------------------------------
const LEVEL_NAMES = {
  '1A': 'Level 1A - No Landmark Workout',
  '1B': 'Level 1B - 20 Navy Seals in 20 min',
  '1C': 'Level 1C - 40 Navy Seals in 20 min',
  '1D': 'Level 1D - 60 Navy Seals in 20 min',
  '2': 'Level 2 - 80 Navy Seals in 20 min',
  '3': 'Level 3 - 100 Navy Seals in 20 min',
  '4': 'Level 4 - 120 Navy Seals in 20 min',
  'grad': 'Graduation - 150 Navy Seals in 20 min',
  'B1': 'Beginner 1 - 20 burpees in 20 min',
  'B2': 'Beginner 2 - 40 burpees in 20 min',
  'B3': 'Beginner 3 - 55 burpees in 20 min',
  'B4': 'Beginner 4 - 70 burpees in 20 min',
  'B5': 'Beginner 5 - 90 burpees in 20 min',
  'B6': 'Beginner 6 - 110 burpees in 20 min',
};

function buildJWT(sa) {
  const now = Math.floor(Date.now() / 1000);
  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
  const payload = Buffer.from(JSON.stringify({
    iss: sa.client_email,
    sub: sa.client_email,
    aud: 'https://oauth2.googleapis.com/token',
    iat: now,
    exp: now + 3600,
    scope: 'https://www.googleapis.com/auth/cloud-platform https://www.googleapis.com/auth/firebase',
  })).toString('base64url');
  const toSign = header + '.' + payload;
  const sig = crypto.createSign('RSA-SHA256');
  sig.write(toSign);
  sig.end();
  return toSign + '.' + sig.sign(sa.private_key, 'base64url');
}

SERVICE_ACCOUNT.private_key = SERVICE_ACCOUNT.private_key.replace(/\\n/g, '\n');

const jwt = buildJWT(SERVICE_ACCOUNT);
let tokenRes;
try {
  tokenRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oauth2.googleapis.com/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'grant_type=' + encodeURIComponent('urn:ietf:params:oauth:grant-type:jwt-bearer') + '&assertion=' + encodeURIComponent(jwt),
  });
} catch (e) {
  throw new Error('OAuth token exchange failed: ' + e.message + ' - Google response: ' + JSON.stringify(e.response?.data || e.cause));
}
if (!tokenRes.access_token) throw new Error('No access_token in response: ' + JSON.stringify(tokenRes));
const token = tokenRes.access_token;
const pid = SERVICE_ACCOUNT.project_id;

let firestoreDocs = [];
let pageToken = '';
do {
  const url = 'https://firestore.googleapis.com/v1/projects/' + pid + '/databases/(default)/documents/users?pageSize=300' + (pageToken ? '&pageToken=' + pageToken : '');
  const res = await this.helpers.httpRequest({ method: 'GET', url, headers: { Authorization: 'Bearer ' + token } });
  firestoreDocs = firestoreDocs.concat(res.documents || []);
  pageToken = res.nextPageToken || '';
} while (pageToken);

const levelByUid = {};
for (const doc of firestoreDocs) {
  const uid = doc.name.split('/').pop();
  levelByUid[uid] = doc.fields?.currentLevelId?.stringValue || null;
}

const uids = Object.keys(levelByUid);
const results = [];

for (let i = 0; i < uids.length; i += 100) {
  const batch = uids.slice(i, i + 100);
  const authRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://identitytoolkit.googleapis.com/v1/projects/' + pid + '/accounts:lookup',
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: JSON.stringify({ localId: batch }),
  });

  for (const u of (authRes.users || [])) {
    if (!u.email) continue;
    const currentLevelId = levelByUid[u.localId] || null;
    results.push({
      json: {
        uid: u.localId,
        email: u.email,
        displayName: u.displayName || u.email.split('@')[0],
        currentLevelId,
        levelName: currentLevelId ? (LEVEL_NAMES[currentLevelId] || currentLevelId) : null,
        hasStarted: !!currentLevelId,
      },
    });
  }
}

return results;
